package com.example.demo.service;

import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import com.example.demo.entity.UserEntity;
import com.example.demo.repository.UserRepository;
import java.util.UUID;

@Service
public class AuthService {

    private final UserRepository userRepository;

    public AuthService(UserRepository userRepository){
        this.userRepository = userRepository;
    }

    @Transactional
    public void generateBackupCodes(String username){
        UserEntity user = userRepository.findByUsername(username);
        for(int i=0; i<10; i++) {
            String backupCode = UUID.randomUUID().toString();
            user.getBackupCodes().add(backupCode);
        }
        userRepository.save(user);
    }

    @Transactional
    public boolean authenticate(String username, String code){
        UserEntity user = userRepository.findByUsername(username);
        if(user.getBackupCodes().contains(code)){
            user.getBackupCodes().remove(code);
            userRepository.save(user);
            return true;
        }
        return false;
    }
}

